-- 092_seed_wccg_content — ports hardcoded shows/hosts/check-ins into the DB (station_wccg). Generated from apps/web/src/data/*.ts.

begin;

-- ── Additive columns (idempotent) ──────────────────────────────────────────
alter table public.shows add column if not exists host_names      text;
alter table public.shows add column if not exists tagline         text;
alter table public.shows add column if not exists show_image_url  text;
alter table public.shows add column if not exists host_image_url  text;
alter table public.shows add column if not exists category        text;

alter table public.hosts add column if not exists youtube_channel text;

alter table public.check_in_locations add column if not exists description text;

-- ── Stream for MixxSquadd Radio (so its show has a valid stream_id) ─────────
insert into public.streams (id, name, slug, category, status, station_id) values
  ('stream_mixsquad', 'MixxSquadd', 'mixsquad', 'HIP_HOP', 'ACTIVE', 'station_wccg')
on conflict (id) do nothing;

-- ── Shows ───────────────────────────────────────────────────────────────────
insert into public.shows
  (id, name, slug, host_names, time_slot, days, description, tagline, gradient,
   image_url, show_image_url, host_image_url, hero_image_class, youtube, podcast_rss,
   segments, is_syndicated, is_active, category, stream_id, station_id)
values
  ('show_streetz_morning', 'Yung Joc and The Streetz Morning Takeover', 'streetz-morning-takeover', 'Yung Joc, Mz Shyneka & Shawty Shawty', '6:00 AM - 10:00 AM', 'Monday - Friday', 'North Carolina''s #1 Hip-Hop morning show on WCCG 104.5 FM, hosted by Yung Joc, Mz Shyneka, and Shawty Shawty. It''s a high-energy mix of the hottest Hip-Hop & R&B, celebrity gossip, viral trending topics, relationship drama (Date Dilemma), wild news (Shawty''s Crazy Report), and non-stop laughs — the unfiltered soundtrack that wakes up the city and the culture every weekday.', 'North Carolina''s #1 Hip-Hop Morning Show', 'from-[#1a0a2e] via-[#16213e] to-[#0f3460]', '/images/hosts/yung-joc.png', 'https://wccg1045fm.com/wp-content/uploads/2025/09/streetz.png', 'https://wccg1045fm.com/wp-content/uploads/2025/11/attachment-thumbnail_new-streetz-pix.png', 'object-cover object-top', '{"channelName":"Streetz Morning Takeover","channelUrl":"https://youtube.com/@WCCG1045FM","searchQuery":"Streetz Morning Takeover WCCG"}'::jsonb, 'https://feeds.simplecast.com/c3z3h1Ug', '["Date Dilemma","Shawty''s Crazy Report","Celebrity Interviews","Trending Topics"]'::jsonb, true, true, 'weekday', 'stream_main', 'station_wccg'),
  ('show_way_up_angela_yee', 'Way Up with Angela Yee', 'way-up-angela-yee', 'Angela Yee', '10:00 AM - 2:00 PM', 'Monday - Friday', 'The syndicated midday Hip-Hop and R&B powerhouse featuring witty, empowering vibes with trending topics, relationship advice, anonymous secrets, and A-list interviews. Angela Yee is the ultimate midday motivator for urban listeners nationwide.', 'The ultimate midday motivator', 'from-[#1a0533] via-[#2d1b69] to-[#1a1a2e]', 'https://wccg1045fm.com/wp-content/uploads/2025/09/angela-yee-new-2.png', 'https://wccg1045fm.com/wp-content/uploads/2025/09/yee-01.png', 'https://wccg1045fm.com/wp-content/uploads/2025/11/angela-yee-tamara-beckwith-ny-post-01.webp', NULL, '{"channelName":"Way Up With Angela Yee","channelUrl":"https://www.youtube.com/@wayupwithyee","channelId":"UCJVR_M2dXZT6uXIapYGHtTA","extraChannelIds":["UCWS_UtIkoPGKODjeJEHMdEg"],"searchQuery":"Way Up With Angela Yee"}'::jsonb, NULL, '["Shine a Light on ''Em","Tell Us a Secret","Rumor Report","Ask Yee"]'::jsonb, true, true, 'weekday', 'stream_main', 'station_wccg'),
  ('show_general_programming_weekday', 'General Programming', 'general-programming-afternoon', 'WCCG', '2:00 PM - 7:00 PM', 'Monday - Friday', 'WCCG 104.5 FM brings you the best in hip hop and R&B during the afternoon drive. Featuring today''s daily mix show theme and the hottest tracks to power your commute home.', 'Afternoon drive with the best hip hop and R&B', 'from-[#0f0c29] via-[#302b63] to-[#24243e]', NULL, NULL, NULL, NULL, NULL, NULL, '[]'::jsonb, false, true, 'weekday', 'stream_main', 'station_wccg'),
  ('show_posted_corner', 'Posted on The Corner', 'posted-on-the-corner', 'Incognito & DJ Misses', '7:00 PM - Midnight', 'Monday - Friday', 'The syndicated weeknight Hip-Hop and R&B party show featuring high-energy vibes, exclusive celebrity interviews, fan-voted Top 7 Countdowns, wild Trending on the Timeline segments, and interactive trivia that turns listeners into the real stars of the show. Airing in over 20 markets including Atlanta, Houston, Dallas, Cleveland, Baltimore, Detroit, Indianapolis, and Raleigh.', 'The syndicated weeknight Hip-Hop party in 20+ markets', 'from-[#0a1628] via-[#1a0a2e] to-[#162447]', '/images/incognito-new.png', '/images/incognito-new.png', '/images/incognito-new.png', NULL, '{"channelName":"Posted On The Corner","channelUrl":"https://www.youtube.com/@PostedOnTheCorner","channelId":"UCB4JlD2jIkXanFehab9CbDw","searchQuery":"Posted on The Corner"}'::jsonb, NULL, '["Top 7 Countdown","Posted on The Corner Trivia","Trending on the Timeline","Celebrity Interviews"]'::jsonb, true, true, 'weekday', 'stream_main', 'station_wccg'),
  ('show_bootleg_kev', 'The Bootleg Kev Show', 'bootleg-kev-show', 'Bootleg Kev, James Andre Jefferson Jr. & DJ Sam I Am', 'Midnight - 6:00 AM', 'Monday - Friday', 'A nationally syndicated hip-hop overnight program featuring exclusive artist interviews, viral freestyles, No Cap News, wild caller roasts, and non-stop bangers. Bootleg Kev, James Andre Jefferson Jr., and DJ Sam I Am target night-shift workers, insomniacs, and late-night culture enthusiasts across 80+ stations with raw, unfiltered hip-hop culture and celebrity access.', 'Overnight hip-hop across 80+ stations', 'from-[#1a0533] via-[#0d1b2a] to-[#1b2838]', 'https://wccg1045fm.com/wp-content/uploads/2025/09/bootleg-kev-new1.png', 'https://wccg1045fm.com/wp-content/uploads/2025/09/bootleg-kev-new1.png', 'https://wccg1045fm.com/wp-content/uploads/2025/11/GAxhqlAXcAAPZOQ.jpg', NULL, '{"channelName":"Bootleg Kev","channelUrl":"https://www.youtube.com/@BootlegKev","channelId":"UCBgOGeH-NL4o2WGutwverqQ","searchQuery":"Bootleg Kev"}'::jsonb, NULL, '["No Cap News","Artist Freestyles","Pop Culture Debates","Listener Call-ins"]'::jsonb, true, true, 'weekday', 'stream_main', 'station_wccg'),
  ('show_abc_news', 'ABC News Updates', 'abc-news', 'ABC News', 'Hourly', 'Monday - Friday', 'Stay informed with ABC News updates airing throughout the day on WCCG 104.5 FM. National and world news coverage keeping you connected to breaking stories and trending topics.', 'National news updates throughout the day', 'from-[#0a0a1a] via-[#1a1a2e] to-[#16213e]', NULL, NULL, NULL, NULL, '{"channelName":"ABC News","channelUrl":"https://www.youtube.com/@ABCNews","channelId":"UCBi2mrWuNuyYy4gbM6fU18Q","searchQuery":"ABC News"}'::jsonb, NULL, '[]'::jsonb, true, true, 'weekday', 'stream_main', 'station_wccg'),
  ('show_streetz_weekend_countdown', 'Yung Joc and the Streetz Weekend Countdown', 'streetz-weekend-countdown', 'Yung Joc, Mz Shyneka & Shawty Shawty', '6:00 AM - 9:00 AM', 'Saturday', 'The Streetz Morning Takeover crew brings the same high energy to Saturday mornings with the Streetz Weekend Countdown. Top tracks, celebrity moments, and the best recaps of the week.', 'Saturday morning countdown of the week''s hottest tracks', 'from-[#1a0a2e] via-[#16213e] to-[#0f3460]', '/images/hosts/yung-joc.png', '/images/shows/streetz-morning-takeover.png', NULL, NULL, NULL, NULL, '[]'::jsonb, true, true, 'saturday', 'stream_main', 'station_wccg'),
  ('show_deja_vu', 'The Deja Vu Show', 'deja-vu-show', 'WCCG', '10:00 AM - 3:00 PM', 'Saturday', 'Take a trip down memory lane with The Deja Vu Show. Featuring classic hip hop, R&B throwbacks, and nostalgic hits that bring the good vibes every Saturday.', 'Classic throwbacks and nostalgic vibes every Saturday', 'from-[#1a1a2e] via-[#2d1b69] to-[#1a0533]', NULL, NULL, NULL, NULL, '{"channelName":"The Deja Vu Show","channelUrl":"https://www.youtube.com/@TheDejaVuShow","channelId":"UCO_M1X6yEa-T1UH_XhWA8Yw","searchQuery":"The Deja Vu Show WCCG"}'::jsonb, NULL, '[]'::jsonb, false, true, 'saturday', 'stream_main', 'station_wccg'),
  ('show_day_party', 'Day Party Radio: The Weekend Top 50', 'day-party-radio', 'WCCG', '3:00 PM - 7:00 PM', 'Saturday', 'Get the party started early with Day Party Radio featuring The Weekend Top 50 countdown. High-energy mixes and the hottest tracks of the week to kick off your Saturday night.', 'The Weekend Top 50 — get the party started before the sun goes down', 'from-[#0f3460] via-[#16213e] to-[#162447]', NULL, NULL, NULL, NULL, NULL, NULL, '[]'::jsonb, false, true, 'saturday', 'stream_main', 'station_wccg'),
  ('show_riich_villianz', 'Riich Villianz Radio', 'riich-villianz-radio', 'DJ Ricovelli, Slim & DJ Tony Neal', '7:00 PM - Midnight', 'Saturday', 'DJ Ricovelli, Slim, and the legendary DJ Tony Neal (founder of Core DJs) take over Saturday nights with Riich Villianz Radio. The hottest mixes, exclusive drops, and non-stop party energy.', 'Saturday night takeover with the hottest DJ mixes', 'from-[#1a0533] via-[#0f0c29] to-[#302b63]', NULL, NULL, NULL, NULL, NULL, NULL, '[]'::jsonb, false, true, 'saturday', 'stream_main', 'station_wccg'),
  ('show_general_programming_sat_overnight', 'Overnights', 'saturday-overnights', 'WCCG', 'Midnight - 6:00 AM', 'Saturday', 'General programming through the early Saturday morning hours featuring the best in hip hop and R&B.', 'Late night general programming', 'from-[#0f0c29] via-[#1a0533] to-[#24243e]', NULL, NULL, NULL, NULL, NULL, NULL, '[]'::jsonb, false, true, 'saturday', 'stream_main', 'station_wccg'),
  ('show_praise_mix', 'Praise Mix at 6am', 'praise-mix', 'WCCG', '6:00 AM - 8:00 AM', 'Sunday', 'Start your Sunday morning with an uplifting mix of gospel music, praise and worship, and inspirational tracks. Part of The Sunday Gospel Caravan on WCCG 104.5 FM.', 'Start your Sunday with praise and worship', 'from-[#1a1a2e] via-[#16213e] to-[#0d1b2a]', NULL, 'https://wccg1045fm.com/wp-content/uploads/2025/12/praisemix-6.png', NULL, NULL, NULL, NULL, '[]'::jsonb, false, true, 'gospel', 'stream_main', 'station_wccg'),
  ('show_grace_plus_nothing', 'Grace Plus Nothing Ministries', 'grace-plus-nothing', 'Apostle Anthony Monds', '8:00 AM - 9:00 AM', 'Sunday', 'Apostle Anthony Monds brings messages of faith, grace, and community as part of the Sunday Gospel Caravan on WCCG 104.5 FM.', 'Messages of faith, grace, and community', 'from-[#1a1a2e] via-[#0d1b2a] to-[#16213e]', NULL, 'https://wccg1045fm.com/wp-content/uploads/2025/10/gpn-1-1024x743-1.png', NULL, NULL, '{"channelName":"Grace Plus Nothing","channelUrl":"https://www.youtube.com/@anthonymonds3736","channelId":"UCRqRVNSRMdIQqZw60bAgN1w","searchQuery":"Grace Plus Nothing Ministries"}'::jsonb, NULL, '[]'::jsonb, false, true, 'gospel', 'stream_main', 'station_wccg'),
  ('show_encouraging_moment', 'The Encouraging Moment', 'encouraging-moment', 'Dr. Tony Haire', '9:00 AM - 10:00 AM', 'Sunday', 'Dr. Tony Haire provides spiritual encouragement, biblical teaching, and hope to the Fayetteville community and beyond every Sunday morning as part of The Sunday Gospel Caravan.', 'Spiritual encouragement and biblical teaching', 'from-[#16213e] via-[#1a1a2e] to-[#0d1b2a]', NULL, 'https://wccg1045fm.com/wp-content/uploads/2025/10/thm-main-1024x743-1.png', NULL, NULL, '{"channelName":"Encouraging Moments","channelUrl":"https://www.youtube.com/@encouraging1moment","channelId":"UCvxWyn4rfcI2H9APhfUIB1Q","searchQuery":"Encouraging Moments Dr Anthony Haire"}'::jsonb, NULL, '[]'::jsonb, false, true, 'gospel', 'stream_main', 'station_wccg'),
  ('show_marvin_sapp', 'The Marvin Sapp Radio Show', 'marvin-sapp-radio-show', 'Bishop Marvin Sapp', '10:00 AM - 12:00 PM', 'Sunday', 'Multi-Grammy nominated gospel artist and pastor Bishop Marvin Sapp brings inspirational conversation, the best in gospel music, and uplifting messages every Sunday morning.', 'Inspirational gospel from a Grammy-nominated artist', 'from-[#1a0533] via-[#2d1b69] to-[#1a1a2e]', NULL, 'https://wccg1045fm.com/wp-content/uploads/2025/10/marvin-sapp12.jpg', NULL, NULL, NULL, NULL, '[]'::jsonb, true, true, 'gospel', 'stream_main', 'station_wccg'),
  ('show_family_fellowship', 'Family Fellowship Worship Center', 'family-fellowship', 'FFWC', '12:00 PM - 1:00 PM', 'Sunday', 'Family Fellowship Worship Center brings their Sunday service to the airwaves with powerful sermons and spiritual guidance.', 'Powerful sermons and spiritual guidance', 'from-[#0d1b2a] via-[#1a1a2e] to-[#16213e]', NULL, 'https://wccg1045fm.com/wp-content/uploads/2025/10/ffwc-1024x743-1.png', NULL, NULL, '{"channelName":"Family Fellowship Worship Center","channelUrl":"https://www.youtube.com/@weareffwc","channelId":"UCxTzK_2da5bZag5WTAbiVzQ","searchQuery":"Family Fellowship Worship Center"}'::jsonb, NULL, '[]'::jsonb, false, true, 'gospel', 'stream_main', 'station_wccg'),
  ('show_progressive_mbc', 'Progressive Missionary Baptist Church', 'progressive-mbc', 'Rev. F. Bernard Fuller', '1:00 PM - 2:00 PM', 'Sunday', 'Reverend F. Bernard Fuller leads Progressive Missionary Baptist Church — relevant, radical, and real faith through strong biblical teaching — broadcast as part of The Sunday Gospel Caravan.', 'Relevant, radical, and real faith', 'from-[#0d1b2a] via-[#16213e] to-[#1a1a2e]', NULL, 'https://wccg1045fm.com/wp-content/uploads/2025/10/progressive-1024x743-1.png', NULL, NULL, '{"channelName":"Progressive Missionary Baptist Church","channelUrl":"https://www.youtube.com/@progressivemissionarybapti7744","channelId":"UCavo4QHyzuMM2FED2W6PwEg","searchQuery":"Progressive Missionary Baptist Church Fayetteville"}'::jsonb, NULL, '[]'::jsonb, false, true, 'gospel', 'stream_main', 'station_wccg'),
  ('show_lewis_chapel', 'Lewis Chapel Baptist Church', 'lewis-chapel', 'Pastor Christopher Stackhouse', '2:00 PM - 3:00 PM', 'Sunday', 'Pastor Christopher Stackhouse leads the Lewis Chapel Baptist Church broadcast every Sunday afternoon as part of The Sunday Gospel Caravan.', 'Inspirational Sunday afternoon messages', 'from-[#1a1a2e] via-[#16213e] to-[#0d1b2a]', NULL, 'https://wccg1045fm.com/wp-content/uploads/2025/10/lewis-chapel-1024x743-1.png', NULL, NULL, '{"channelName":"Lewis Chapel Missionary Baptist Church","channelUrl":"https://www.youtube.com/@lewischapelmissionarybapti4024","channelId":"UCOe1fQxFPHNf3N7Rb55ySTA","searchQuery":"Lewis Chapel Missionary Baptist Church"}'::jsonb, NULL, '[]'::jsonb, false, true, 'gospel', 'stream_main', 'station_wccg'),
  ('show_general_programming_sunday', 'General Programming', 'general-programming-sunday', 'WCCG', '3:00 PM - 7:00 PM', 'Sunday', 'Wind down the weekend with the best in R&B and hip hop as we wrap up Sunday and get you ready for the week ahead. Featuring the Shorty Corleone Gogo Mix Show at 5pm.', 'Wrapping up the weekend with the best music', 'from-[#0f3460] via-[#16213e] to-[#1a1a2e]', NULL, NULL, NULL, NULL, NULL, NULL, '[]'::jsonb, false, true, 'sunday', 'stream_main', 'station_wccg'),
  ('show_gogo_mix', 'Crank with Shorty Corleone', 'crank-shorty-corleone', 'Shorty Corleone', '5:00 PM - 6:00 PM', 'Sunday', 'Go-Go legend Shorty Corleone cranks up Fayetteville with one hour of pure DMV fire — blending D.C.''s pocket-heavy classics from Rare Essence and Chuck Brown with fresh Hip-Hop remixes, live scratches, and call-in shoutouts. A Rare Essence alumnus with a Warner Bros. publishing deal at age 14, Corleone also co-hosts Sirius XM''s syndicated Crank Radio on H.U.R. Voices.', 'One hour of pure DMV fire every Sunday', 'from-[#302b63] via-[#0f0c29] to-[#1a0533]', 'https://wccg1045fm.com/wp-content/uploads/2025/11/shorty-corleone-new.png', 'https://wccg1045fm.com/wp-content/uploads/2025/11/shorty-corleone-new.png', 'https://wccg1045fm.com/wp-content/uploads/2025/11/shorty-corleone.png', NULL, NULL, NULL, '[]'::jsonb, false, true, 'sunday', 'stream_main', 'station_wccg'),
  ('show_sunday_snacks', 'Sunday Snacks', 'sunday-snacks', 'DJ Ike GDA & DJ IzzyNice', '7:00 PM - Midnight', 'Sunday', 'The Wright Brothers of the turntables deliver five straight hours of soul food for your speakers: classic throwbacks, brand-new heat, exclusive remixes, and live scratches that make the subs knock. DJ Ike GDA, a veteran turntablist and Carolina Trendsetter with three decades in Southern hip-hop, teams with DJ IzzyNice, a high-octane mixer with 20+ years in Carolina nightlife.', 'Five hours of soul food for your speakers', 'from-[#302b63] via-[#0f0c29] to-[#24243e]', '/images/WRIGHT-BROS.png', '/images/WRIGHT-BROS.png', '/images/WRIGHT-BROS.png', 'object-cover object-center', NULL, NULL, '[]'::jsonb, false, true, 'sunday', 'stream_main', 'station_wccg'),
  ('show_island_frequency', 'The Island Frequency Podcast', 'island-frequency-podcast', 'DJ Daffie', 'Sunday Evenings', 'Sunday', 'DJ Daffie brings Caribbean and island vibes to the airwaves with The Island Frequency Podcast. A DJ and performer from Queens/Long Island, New York, Daffie blends dancehall, soca, reggae, and Afrobeats with hip-hop for a unique island-urban fusion.', 'Caribbean vibes and island-urban fusion', 'from-[#0f3460] via-[#16213e] to-[#1a0533]', 'https://wccg1045fm.com/wp-content/uploads/2026/02/island-freq.png', 'https://wccg1045fm.com/wp-content/uploads/2026/02/island-freq.png', 'https://wccg1045fm.com/wp-content/uploads/2026/02/IMG_5248-5-scaled.jpg', NULL, NULL, NULL, '[]'::jsonb, false, true, 'sunday', 'stream_main', 'station_wccg'),
  ('show_mixsquad_radio', 'MixxSquadd Radio', 'mixsquad-radio', 'DJ Ricovelli, DJ SpinWiz, DJ Rayn, DJ TommyGee Mixx & DJ Yodo', '24/7', 'Every Day', 'MixxSquadd Radio delivers non-stop DJ mixes 24/7 on its own dedicated stream. Featuring DJ Ricovelli, DJ SpinWiz, DJ Rayn, DJ TommyGee Mixx, and DJ Yodo with the best in hip hop, R&B, dancehall, and club mixes.', '24/7 non-stop DJ mixes on a dedicated stream', 'from-[#ec4899] via-[#be185d] to-[#831843]', NULL, NULL, NULL, NULL, NULL, NULL, '[]'::jsonb, false, true, 'mixsquad', 'stream_mixsquad', 'station_wccg'),
  ('show_big_cas', 'Big Cas', 'big-cas', 'Big Cas', 'On Demand', 'New episodes weekly', 'Big Cas brings Fayetteville the culture unfiltered — hip-hop news, reactions, interviews, and the stories moving the 910. Straight talk from Fayettenam''s own. Contains explicit language.', 'Fayettenam culture, unfiltered', 'from-[#1a0533] via-[#2d0a4e] to-[#0a0a1a]', NULL, NULL, NULL, NULL, '{"channelName":"BigCas910 TV","channelUrl":"https://www.youtube.com/@bigcas910","channelId":"UCQmsI0AAbXvTevWkqMIBU-Q","searchQuery":"BigCas910 TV"}'::jsonb, NULL, '[]'::jsonb, false, true, 'mixsquad', 'stream_main', 'station_wccg'),
  ('show_carolina_effect', 'The Carolina Effect', 'carolina-effect', 'WCCG', 'On Demand', 'Weekly', 'A deep dive into Carolina culture — music, sports, lifestyle, and the people shaping the Carolinas. Real conversations with local influencers, artists, and community leaders.', 'The pulse of Carolina culture', 'from-[#1e3a5f] via-[#0d2137] to-[#0a0a0f]', NULL, NULL, NULL, NULL, NULL, NULL, '[]'::jsonb, false, true, 'weekday', 'stream_main', 'station_wccg'),
  ('show_inside_the_lines', 'Inside The Lines with James Sanders III', 'inside-the-lines', 'James Sanders III', 'On Demand', 'Weekly', 'Sports analyst James Sanders III goes beyond the box scores to bring listeners the stories, strategy, and culture behind the games. From college hoops to the NFL, Inside The Lines delivers expert analysis with a Carolina perspective.', 'Beyond the box scores', 'from-[#003087] via-[#001f5c] to-[#0a0a0f]', NULL, NULL, NULL, NULL, NULL, NULL, '[]'::jsonb, false, true, 'weekday', 'stream_main', 'station_wccg'),
  ('show_friday_night_shockwave', 'Friday Night Shockwave', 'friday-night-shockwave', 'WCCG', 'Friday Nights', 'Friday', 'The ultimate Friday night experience — non-stop bangers, exclusive mixes, and high-voltage energy to kick off your weekend. Friday Night Shockwave delivers the hardest-hitting playlist on Carolina radio.', 'High-voltage Friday nights', 'from-[#dc2626] via-[#7401df] to-[#0a0a0f]', NULL, NULL, NULL, NULL, NULL, NULL, '[]'::jsonb, false, true, 'weekday', 'stream_main', 'station_wccg')
on conflict (id) do update set
  name           = excluded.name,
