  segments       = excluded.segments,
  is_syndicated  = excluded.is_syndicated,
  is_active      = excluded.is_active,
  category       = excluded.category,
  stream_id      = excluded.stream_id,
  station_id     = excluded.station_id;

-- ── Hosts ───────────────────────────────────────────────────────────────────
insert into public.hosts
  (id, name, slug, role, bio, avatar_url, social_links, youtube_channel,
   youtube_channel_id, is_syndicated, is_active, category, station_id)
values
  ('host_yung_joc', 'Yung Joc', 'yung-joc', 'Host', 'Rapper, DJ, and radio personality Yung Joc brings high energy and unfiltered takes to the Streetz Morning Takeover. Known for his hit ''It''s Goin'' Down'' and his dynamic presence on Love & Hip Hop Atlanta, Joc delivers the hottest conversations, celebrity interviews, and the best morning mix of hip hop and R&B every weekday.', '/images/hosts/yung-joc.png', '[{"platform":"instagram","url":"https://instagram.com/jaborafaeldavismcintyre","label":"@jaborafaeldavismcintyre"},{"platform":"twitter","url":"https://x.com/IBLOCKYOU","label":"@IBLOCKYOU"}]'::jsonb, NULL, NULL, true, true, 'main', 'station_wccg'),
  ('host_mz_shyneka', 'Mz. Shyneka', 'mz-shyneka', 'Co-Host', 'Mz. Shyneka is the co-host of the Streetz Morning Takeover, bringing her witty personality, sharp commentary, and undeniable chemistry with the crew. She keeps the conversation real and the energy high every morning.', NULL, '[{"platform":"instagram","url":"https://instagram.com/mikiamz.shyneka","label":"@mikiamz.shyneka"}]'::jsonb, NULL, NULL, true, true, 'main', 'station_wccg'),
  ('host_shawty_shawty', 'Shawty Shawty', 'shawty-shawty', 'Co-Host', 'Shawty Shawty rounds out the Streetz Morning Takeover crew with his unique perspective and humor. Together with Yung Joc and Mz. Shyneka, he helps deliver the morning show that wakes up the streets.', NULL, '[]'::jsonb, NULL, NULL, true, true, 'main', 'station_wccg'),
  ('host_dj_swin', 'DJ Swin', 'dj-swin', 'DJ', 'DJ Swin keeps the music flowing as the official DJ of the Streetz Morning Takeover. His mixes set the tone every morning with the perfect blend of hip hop, R&B, and trending tracks.', NULL, '[]'::jsonb, NULL, NULL, true, true, 'main', 'station_wccg'),
  ('host_et_cali', 'ET Cali', 'et-cali', 'Fill-In', 'ET Cali serves as a fill-in host for the Streetz Morning Takeover, stepping in with his own brand of energy and entertainment when the crew needs backup.', NULL, '[]'::jsonb, NULL, NULL, true, true, 'main', 'station_wccg'),
  ('host_angela_yee', 'Angela Yee', 'angela-yee', 'Host', 'Angela Yee is a media mogul, entrepreneur, and the host of Way Up with Angela Yee, syndicated nationally through Premiere Networks/iHeartRadio. Previously co-hosting the legendary Breakfast Club for over a decade, Angela brings celebrity interviews, relationship advice, trending topics, and cultural commentary to midday radio.', '/images/hosts/angela-yee.png', '[{"platform":"instagram","url":"https://instagram.com/angelayee","label":"@angelayee"},{"platform":"twitter","url":"https://x.com/angelayee","label":"@angelayee"},{"platform":"youtube","url":"https://youtube.com/@wayupwithyee","label":"@wayupwithyee"}]'::jsonb, '@wayupwithyee', 'UCJVR_M2dXZT6uXIapYGHtTA', true, true, 'main', 'station_wccg'),
  ('host_incognito', 'Incognito', 'incognito', 'Host', 'Incognito is the voice of Posted on the Corner, syndicated in 20+ markets nationwide. Known as Ncognito on some platforms, he delivers the hardest hip hop, exclusive freestyles, and unfiltered commentary every evening. From new music drops to street culture, The Corner is where the streets meet the airwaves.', '/images/hosts/incognito.png', '[{"platform":"instagram","url":"https://instagram.com/ncognito","label":"@ncognito"},{"platform":"twitter","url":"https://x.com/ncognito","label":"@ncognito"}]'::jsonb, NULL, NULL, true, true, 'main', 'station_wccg'),
  ('host_dj_misses', 'DJ Misses', 'dj-misses', 'Co-Host', 'DJ Misses co-hosts Posted on the Corner alongside Incognito, keeping the mixes fresh and the energy up every evening. Her skills behind the decks complement the raw takes and conversation.', NULL, '[]'::jsonb, NULL, NULL, true, true, 'main', 'station_wccg'),
  ('host_bootleg_kev', 'Bootleg Kev', 'bootleg-kev', 'Host', 'Bootleg Kev is a nationally syndicated radio host through Premiere Networks, known for his exclusive interviews with the biggest names in hip hop. With 468K+ YouTube subscribers, Kev connects listeners with first-listen sessions, behind-the-scenes industry stories, and breaking music from coast to coast.', NULL, '[{"platform":"youtube","url":"https://youtube.com/@bootlegkev","label":"@bootlegkev"},{"platform":"instagram","url":"https://instagram.com/bootlegkev","label":"@bootlegkev"},{"platform":"twitter","url":"https://x.com/bootlegkev","label":"@bootlegkev"}]'::jsonb, '@bootlegkev', 'UCBgOGeH-NL4o2WGutwverqQ', true, true, 'main', 'station_wccg'),
  ('host_shorty_corleone', 'Shorty Corleone', 'shorty-corleone', 'Host', 'Shorty Corleone brings certified bangers, underground hip hop, and the best in Southern rap every weeknight on Crank. From trap classics to new fire, Crank is the soundtrack for the late night.', '/images/hosts/shorty-corleone.png', '[]'::jsonb, NULL, NULL, false, true, 'main', 'station_wccg'),
  ('host_dj_ricovelli', 'DJ Ricovelli', 'dj-ricovelli', 'DJ', 'DJ Ricovelli is a core member of both Rich Villianz Radio and MixxSquadd Radio. As one of the featured Saturday night DJs, he brings high-energy sets blending hip hop, trap, and club tracks to keep the party going all night.', '/images/hosts/dj-ricoveli.png', '[]'::jsonb, NULL, NULL, false, true, 'weekend', 'station_wccg'),
  ('host_dj_tony_neal', 'DJ Tony Neal', 'dj-tony-neal', 'DJ', 'DJ Tony Neal is the founder of Core DJs, one of the most influential DJ coalitions in the industry. He brings his legendary mixing skills and deep industry connections to Rich Villianz Radio every Saturday night.', '/images/hosts/dj-tony-neal.png', '[{"platform":"website","url":"https://djtonyneal.com","label":"djtonyneal.com"},{"platform":"instagram","url":"https://instagram.com/djtonyneal","label":"@djtonyneal"}]'::jsonb, NULL, NULL, false, true, 'weekend', 'station_wccg'),
  ('host_carolina_trendsetter', 'Carolina Trendsetter', 'carolina-trendsetter', 'DJ', 'Carolina Trendsetter anchors Sunday Snacks alongside DJ Ike GDA and DJ Izzynice, bringing the best in regional hip hop and DJ mixes every Sunday night to close out the weekend.', NULL, '[]'::jsonb, NULL, NULL, false, true, 'sunday', 'station_wccg'),
  ('host_dj_ike_gda', 'DJ Ike GDA', 'dj-ike-gda', 'DJ', 'DJ Ike GDA is part of the Sunday Snacks crew, delivering club-ready mixes and the hottest tracks to wrap up the weekend right.', '/images/hosts/dj-ike-gda.png', '[]'::jsonb, NULL, NULL, false, true, 'sunday', 'station_wccg'),
  ('host_dj_izzynice', 'DJ Izzynice', 'dj-izzynice', 'DJ', 'DJ Izzynice rounds out the Sunday Snacks team, bringing smooth transitions and eclectic selections to the Sunday night mix.', '/images/hosts/dj-izzynice.png', '[]'::jsonb, NULL, NULL, false, true, 'sunday', 'station_wccg'),
  ('host_marvin_sapp', 'Bishop Marvin Sapp', 'marvin-sapp', 'Bishop', 'Bishop Marvin Sapp is a multi-Grammy nominated gospel artist and pastor. The Marvin Sapp Radio Show blends inspirational conversation, gospel music, and uplifting messages every Sunday morning. Known worldwide for his timeless hit ''Never Would Have Made It.''', NULL, '[{"platform":"instagram","url":"https://instagram.com/bishopmarvinlsapp","label":"@bishopmarvinlsapp"}]'::jsonb, NULL, NULL, true, true, 'gospel', 'station_wccg'),
  ('host_apostle_monds', 'Apostle Anthony Monds', 'apostle-monds', 'Pastor', 'Apostle Anthony Monds leads the Grace Plus Nothing Ministries broadcast every Sunday morning, sharing messages of faith, grace, and community as part of the Sunday Gospel Caravan on WCCG.', NULL, '[]'::jsonb, NULL, NULL, false, true, 'gospel', 'station_wccg'),
  ('host_dr_haire', 'Dr. Anthony Haire', 'dr-haire', 'Pastor', 'Dr. Anthony Haire hosts Encouraging Moments, a Sunday morning broadcast that provides spiritual encouragement, biblical teaching, and hope to the Fayetteville community and beyond.', NULL, '[]'::jsonb, NULL, NULL, false, true, 'gospel', 'station_wccg'),
  ('host_pastor_davenport', 'Pastor Dr. T.L. Davenport', 'pastor-davenport', 'Pastor', 'Pastor Dr. T.L. Davenport leads the Family Fellowship Worship Center broadcast, bringing powerful Sunday sermons and spiritual guidance to the WCCG 104.5 FM audience.', NULL, '[]'::jsonb, NULL, NULL, false, true, 'gospel', 'station_wccg'),
  ('host_rev_fuller', 'Rev. F. Bernard Fuller', 'rev-fuller', 'Pastor', 'Rev. F. Bernard Fuller brings the Sunday service from Progressive Missionary Baptist Church to the airwaves, reaching the community with faith-based programming each week.', NULL, '[]'::jsonb, NULL, NULL, false, true, 'gospel', 'station_wccg'),
  ('host_dr_stackhouse', 'Dr. Christopher Stackhouse, Sr.', 'dr-stackhouse', 'Pastor', 'Dr. Christopher Stackhouse, Sr. leads the Lewis Chapel Missionary Baptist Church broadcast every Sunday afternoon, providing inspirational messages and worship to the Fayetteville area.', NULL, '[]'::jsonb, NULL, NULL, false, true, 'gospel', 'station_wccg'),
  ('host_dj_spinwiz', 'DJ SpinWiz', 'dj-spinwiz', 'DJ', 'DJ SpinWiz is part of the MixxSquadd Radio roster, contributing to the 24/7 DJ mix stream with high-energy sets and creative blends.', '/images/hosts/dj-spinwiz.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_rayn', 'DJ Rayn', 'dj-rayn', 'DJ', 'DJ Rayn brings smooth transitions and diverse track selections to the MixxSquadd Radio 24/7 stream.', '/images/hosts/dj-rayn.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_tommygee', 'DJ TommyGee Mixx', 'dj-tommygee', 'DJ', 'DJ TommyGee Mixx is a featured DJ on MixxSquadd Radio, known for his party-rocking mixes that keep the energy going around the clock.', '/images/hosts/dj-tommygeemixx.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_yodo', 'DJ Yodo', 'dj-yodo', 'DJ', 'DJ Yodo rounds out the MixxSquadd Radio lineup, delivering non-stop mixes that span hip hop, R&B, dancehall, and more.', '/images/hosts/dj-yodo.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_chuck_t', 'DJ Chuck T', 'dj-chuck-t', 'DJ', 'DJ Chuck T is a legendary mixtape king and one of the most respected DJs in the Carolinas. Known for breaking records and rocking crowds, he brings certified street heat to the MixxSquadd.', '/images/hosts/dj-chuck-t.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_daddyblack', 'DJ DaddyBlack', 'dj-daddyblack', 'DJ', 'DJ DaddyBlack delivers raw energy and seamless transitions on MixxSquadd Radio, keeping the vibes right with his signature blends.', '/images/hosts/dj-daddyblack.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_daffie', 'DJ Daffie', 'dj-daffie', 'DJ', 'DJ Daffie keeps the party moving with infectious energy and creative mixes spanning hip hop, R&B, and Afrobeats on MixxSquadd Radio.', '/images/hosts/dj-daffie.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_dane_dinero', 'DJ Dane Dinero', 'dj-dane-dinero', 'DJ', 'DJ Dane Dinero brings a versatile style to MixxSquadd Radio, moving effortlessly between genres and keeping every set fresh.', '/images/hosts/dj-dane-dinero.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_itanist', 'DJ Itanist', 'dj-itanist', 'DJ', 'DJ Itanist is a creative force on MixxSquadd Radio, known for his innovative blends and electrifying live sets.', '/images/hosts/dj-itanist.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_jay_b', 'DJ Jay B', 'dj-jay-b', 'DJ', 'DJ Jay B brings smooth vibes and hard-hitting drops to MixxSquadd Radio, curating the perfect blend of hip hop and R&B.', '/images/hosts/dj-jay-b.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_juice', 'DJ Juice', 'dj-juice', 'DJ', 'DJ Juice serves up premium mixes on MixxSquadd Radio, blending old school classics with new school heat.', '/images/hosts/dj-juice.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_killako', 'DJ Killako', 'dj-killako', 'DJ', 'DJ Killako brings the energy with hard-hitting trap and hip hop mixes that keep the MixxSquadd Radio listeners locked in.', '/images/hosts/dj-killako.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_kingviv', 'DJ KingViv', 'dj-kingviv', 'DJ', 'DJ KingViv reigns over the turntables with regal precision, delivering sets that span hip hop, dancehall, and Afrobeats on MixxSquadd Radio.', '/images/hosts/dj-kingviv.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_lj', 'DJ LJ', 'dj-lj', 'DJ', 'DJ LJ keeps the crowd moving with seamless transitions and genre-bending mixes on MixxSquadd Radio.', '/images/hosts/dj-lj.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_loudiamonds', 'DJ Lou Diamonds', 'dj-loudiamonds', 'DJ', 'DJ Lou Diamonds shines bright on MixxSquadd Radio, delivering polished mixes with a signature style that keeps listeners coming back.', '/images/hosts/dj-loudiamonds.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_official', 'DJ Official', 'dj-official', 'DJ', 'DJ Official lives up to the name with certified club-ready mixes and high-energy sets on MixxSquadd Radio.', '/images/hosts/dj-official.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_swazzey', 'DJ Swazzey', 'dj-swazzey', 'DJ', 'DJ Swazzey brings the sauce with creative blends and innovative mixes that push boundaries on MixxSquadd Radio.', '/images/hosts/dj-swazzey.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_t_money', 'DJ T-Money', 'dj-t-money', 'DJ', 'DJ T-Money delivers premium mixes with a focus on Southern hip hop and club bangers on MixxSquadd Radio.', '/images/hosts/dj-t-money.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_tonelo', 'DJ Tonelo', 'dj-tonelo', 'DJ', 'DJ Tonelo sets the tone with smooth R&B blends and hard-hitting hip hop on MixxSquadd Radio.', '/images/hosts/dj-tonelo.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_weezy', 'DJ Weezy', 'dj-weezy', 'DJ', 'DJ Weezy brings non-stop energy with bass-heavy mixes and creative drops on MixxSquadd Radio.', '/images/hosts/dj-weezy.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
  ('host_dj_whosane', 'DJ Whosane', 'dj-whosane', 'DJ', 'DJ Whosane keeps the streets talking with certified mixes that blend trap, hip hop, and club music on MixxSquadd Radio.', '/images/hosts/dj-whosane.png', '[]'::jsonb, NULL, NULL, false, true, 'mixsquad', 'station_wccg'),
